// Parse report and extract relevant data for git commit
const fs = require('fs');
const filePath = $input.first().json.path;
const fileName = filePath.split('/').pop();

// Validate file matches expected pattern: *_batch*.md
const batchPattern = /(.+)_batch(\d+)\.md$/;
const match = fileName.match(batchPattern);

if (!match) {
  return [{ json: { should_commit: false, reason: 'Not a batch report file', file: fileName } }];
}

const taskName = match[1];
const batchNumber = parseInt(match[2]);

const content = fs.readFileSync(filePath, 'utf8');

// Parse status
let status = 'UNKNOWN';
const statusMatch = content.match(/##\s*Status:\s*(PASS|FAIL|PARTIAL|BLOCKED)/i);
if (statusMatch) {
  status = statusMatch[1].toUpperCase();
}

// Parse task ID
let taskId = 'UNKNOWN';
const taskIdMatch = content.match(/##\s*Task\s*ID:\s*(\S+)/i);
if (taskIdMatch) {
  taskId = taskIdMatch[1];
}

// Parse files changed from CHANGES MADE section
const filesChanged = [];
const changesSection = content.match(/### CHANGES MADE[\s\S]*?(?=###|$)/i);
if (changesSection) {
  const lines = changesSection[0].split('\n');
  for (const line of lines) {
    // Match patterns like: - [filepath]: description  OR  - filepath: description
    const fileMatch = line.match(/^\s*-\s*\[?([^\]:\n]+?)\]?\s*:/); 
    if (fileMatch) {
      const fp = fileMatch[1].trim();
      // Filter out non-file entries
      if (fp && !fp.startsWith('#') && fp.includes('/') || fp.includes('.')) {
        filesChanged.push(fp);
      }
    }
  }
}

// Parse objective from report
let objective = taskName.replace(/_/g, ' ');
const objectiveMatch = content.match(/(?:objective|purpose|summary):\s*(.+)/i);
if (objectiveMatch) {
  objective = objectiveMatch[1].trim();
}

return [{
  json: {
    should_commit: status === 'PASS',
    status: status,
    task_id: taskId,
    task_name: taskName,
    batch_number: batchNumber,
    report_file: filePath,
    file_name: fileName,
    files_changed: filesChanged,
    objective: objective,
    parsed_at: new Date().toISOString()
  }
}];

// Build the git commit command with a structured message
const data = $input.first().json;

// Inherit parsed fields from the previous chain
// Note: data comes from executeCommand output, so we use $('Parse Report for Commit')
const parsed = $('Parse Report for Commit').first().json;

const commitMsg = [
  `Batch ${parsed.batch_number} [${parsed.task_id}]: ${parsed.objective}`,
  '',
  `Status: ${parsed.status}`,
  `Report: ${parsed.file_name}`,
  `Files: ${parsed.files_changed.length > 0 ? parsed.files_changed.join(', ') : 'report only'}`,
  '',
  `Automated commit by N8n audit trail workflow`,
  `Timestamp: ${parsed.parsed_at}`
].join('\n');

return [{
  json: {
    commit_message: commitMsg,
    task_id: parsed.task_id,
    batch_number: parsed.batch_number,
    file_name: parsed.file_name,
    files_changed: parsed.files_changed
  }
}];

// Verify the commit succeeded and extract the commit hash
const output = $input.first().json.stdout || $input.first().json.stderr || '';
const commitData = $('Build Commit Message').first().json;

let commitHash = 'unknown';
const hashMatch = output.match(/\[\w+\s+([a-f0-9]+)\]/);
if (hashMatch) {
  commitHash = hashMatch[1];
}

const success = output.includes('file changed') || 
                output.includes('files changed') || 
                output.includes('insertions') ||
                output.includes('create mode');

return [{
  json: {
    commit_success: success,
    commit_hash: commitHash,
    commit_output: output.substring(0, 500),
    task_id: commitData.task_id,
    batch_number: commitData.batch_number,
    file_name: commitData.file_name,
    files_committed: commitData.files_changed,
    committed_at: new Date().toISOString()
  }
}];

